class Solution:
    def smallestNumber(self, num: int) -> int:
        if num == 0:
            return 0
        neg = num < 0
        s = str(abs(num))
        digits = list(s)
        if neg:
            digits.sort(reverse=True)
            return -int(''.join(digits))
        else:
            digits.sort()
            if digits[0] == '0':
                i = 1
                while i < len(digits) and digits[i] == '0':
                    i += 1
                if i < len(digits):
                    digits[0], digits[i] = digits[i], digits[0]
            return int(''.join(digits))
```
efficiency: HIGH
time complexity: O(d log d) where d is the number of digits
space complexity: O(d)
energy implications: LOW
explanation: Convert the absolute value to a string, sort the digits ascending for positive numbers (descending for negative), then swap the first non-zero digit with the leading zero if necessary to avoid leading zeros.

